-- Insert 18 new grant programs into investors table
-- Skipping 'Export Market Development Grant (EMDG)' and 'R&D Tax Incentives' (already exist)

INSERT INTO public.investors (name, description, investor_type, location, website, sector_focus, stage_focus, check_size_min, check_size_max, contact_email, details, is_featured) VALUES
('Agrifutures Australia RD&E Investment', 'AgriFutures Australia RD&E Investment provides funding for organisations to help conduct research that will improve the sustainability and profitability of new and established rural services.', 'grant', 'National', 'https://business.gov.au/grants-and-programs/Agrifutures-Australia-RDE-Investment', ARRAY['Agriculture','Rural Industries'], ARRAY['Startup/Seed','Growth','Enterprise'], NULL, NULL, 'info@agrifutures.com.au', '{"administrator": "AgriFutures Australia", "benefit": "Funding varies.", "eligibility": "Organisations conducting RD&E of direct benefit to specified Australian rural industries; align with AgriFutures Strategic Plan (2022-2027), RD&E priorities in annual plans/industry RD&E plans; comply with reporting; disseminate IP/materials; account for similar existing projects.", "funding_covers": "Funding for research, development, and extension (RD&E) activities to strengthen and future-proof established and emerging rural industries."}'::jsonb, false),

('Assigned Production Investment - Games', 'This program supports the Victorian digital games development sector by assisting a broad range of companies and creators to produce and market a wide spectrum of digital games.', 'grant', 'Victoria', 'https://www.film.vic.gov.au/funding/games-funding', ARRAY['Digital Games','Interactive Media'], ARRAY['Startup/Seed','Growth'], NULL, 500000, 'contact@vicscreen.vic.gov.au', '{"administrator": "Film Victoria Australia", "benefit": "$80,000 towards a prototype, $150,000 for a vertical slice, and up to $300,000 for production work", "eligibility": "Australian company based/operating in Victoria 6+ months or Australian citizen/PR resident in Victoria 6+ months; original digital games with clear plans for development/market; 50%+ applicant contribution; no gambling/pay-to-win; DEI commitments; appropriate First Peoples key creatives if applicable", "funding_covers": "Staffing, mentors/consultants, legal/accounting fees, prototype/vertical slice development, business dev/publishing assistance, marketing/audience engagement, localisation/porting, post-release content (as assigned production investment with equity assigned to applicant)"}'::jsonb, false),

('Business of Agriculture Grant', 'As part of the SproutX''s Pre-Accelerator Program "Business of Agriculture", the program is offering cohort members funding to kick start their agtech startup journey.', 'grant', 'Victoria', 'https://www.sproutx.com.au/pre-accelerator', ARRAY['Agriculture','Rural Industries'], ARRAY['Pre-Seed','Startup/Seed'], 1000, 10000, 'info@sproutx.com.au', '{"administrator": "SproutX", "benefit": "2000", "eligibility": "New entrants to agtech ecosystem including tertiary research, academic, corporate R&D participants, non-traditional entrepreneurs like farmers; Victorian focus; completion of program milestones", "funding_covers": "Bursaries up to $10,000, $1,000 cash + $10,000 services upon milestones; mentorship, experiential learning, farm tours, networking with primary producers, startups, industry leaders"}'::jsonb, false),

('Circular Economy Business Support Fund – Round 3', 'Round 3 of the Circular Economy Business Support Fund supports individual organisations and Collaborative Partnerships with projects that improve the capability and capacity of Victorian industry to identify, implement, commercialise, and scale circular solutions. These projects prevent, minimise or eliminate waste and pollution and keep products or materials in use - at their highest value - for longer. Projects must improve the environmental outcomes of products, services, industries, suppl...', 'grant', 'Victoria', 'https://www.cebic.vic.gov.au/grants-funding-and-investment/grants-and-funding/circular-economy-business-support-fund-round-3', ARRAY['Circular Economy','Sustainability'], ARRAY['Enterprise'], 50000, 1000000, 'grants.enquiries@sustainability.vic.gov.au', '{"administrator": "Sustainability Victoria", "benefit": "Each project can receive a grant between $50,000 and $1,000,000 (ex GST).", "eligibility": "Australian businesses/NFPs/social enterprises/industry groups with ABN active 2+ years; co-contribution (varies, e.g. 1:2); projects improve circular economy capability/capacity in Victoria; pass due diligence", "funding_covers": "Implementation and identification of circular economy business models, products, services, markets; project costs (staff, equipment, feasibility studies, capability building); reduce waste, increase reuse"}'::jsonb, false),

('City of Melbourne - Small Business & Social Enterprise Grant', 'For businesses in the City of Melbourne, receive grant funding in one of the 4 cateogires: - Development (business validation) - Start-up (new and creative businesses) - Expansion (existing businesses expanding) - Export (overseas market expansion)', 'grant', 'Melbourne, VIC', 'https://www.melbourne.vic.gov.au/business/grants-tenders/small-business-grants/Pages/small-business-grants.aspx', ARRAY['Social Enterprise','Circular Economy'], ARRAY['Startup/Seed','Growth'], NULL, 20000, 'businessfunding@melbourne.vic.gov.au', '{"administrator": "City of Melbourne", "benefit": "Up to $30,000", "eligibility": "Valid ABN/ACN; meets social enterprise definition; appropriate legal structure (sole trader, company, cooperative, partnership); no outstanding debts to City of Melbourne; financial viability via business plan; sustainable practices per Australian ethical charter; able to commence upon grant receipt and acquit within 12 months. Not for political orgs, govt agencies, fundraising primary, etc.", "funding_covers": "Establishment, development, and expansion of sustainable social enterprises; capital costs for projects (not general operational expenses like rent, utilities, wages)"}'::jsonb, false),

('City of Sydney Innovation Grant', 'Startups and SME looking to reduce their carbon footprint and who operate in the City of Sydney.', 'grant', 'NSW', 'https://www.cityofsydney.nsw.gov.au/cultural-support-funding/innovation-and-ideas-grant', ARRAY['Sustainability','Technology','Social Innovation'], ARRAY['Startup/Seed','Growth'], 10000, 50000, 'communitygrants@cityofsydney.nsw.gov.au', '{"administrator": "City of Sydney", "benefit": "Matched funding up to $80,000 for 50% of eligible costs", "eligibility": "Not-for-profits, incorporated associations, corporations, co-operatives, trustees of trusts; operate in City of Sydney LGA or demonstrate significant benefit to area; for-profits must match funding; active ABN if business; no duplication of services; projects align with priorities like innovative economy, inclusion, resilience", "funding_covers": "Cash funding for research/feasibility studies, pilot projects, demonstration projects, best practice toolkits, new technologies/platforms, circular economy ideas; up to $5,000 capital/equipment; value-in-kind venue hire; multi-year up to 3 years (not core operational costs)"}'::jsonb, false),

('CSIRO Kick-Start Program', 'For businesses who want to utilise CSIRO expertise to undertake research activities to research, develop or test new products/processes. Australian businesses focusing on agriculture and food; Data61; health and biosecurity; land, water, ocean, atmosphere, energy, mineral resources, astonomy; Australian fauna and National Facilities and collections are eligible.', 'grant', 'National', 'https://www.csiro.au/en/work-with-us/funding-programs/sme/csiro-kick-start/about', ARRAY['Agriculture','Energy','Health','Manufacturing','Technology','Environment'], ARRAY['Startup/Seed','Series A-B'], 10000, 50000, 'kickstart@csiro.au', '{"administrator": "Commonwealth Scientific and Industrial Research Organization (CSIRO)", "benefit": "Matched funding of $10,000-$50,000", "eligibility": "- Australian-registered business (ACN/ICN, GST-registered, primary place of business in Australia; no foreign subsidiaries); - Turnover/expenses < $10M or <3 years trading; - Can provide cash-matched funding; - Projects: new idea R&D, novel product/process dev/test; <1 year; min total cost $20k; via eligible CSIRO units", "funding_covers": "Matched CSIRO voucher for R&D project costs: researcher salaries/on-costs, travel/accommodation, admin/overheads, consumables/external services/contractors (\u226420% budget); excludes capital/infrastructure"}'::jsonb, false),

('Export Assistance Grant Program', 'To help NSW businesses recover from drought, bushfires and COVID-19 by providing co-funding to identify and access new export markets and re-enter previous export markets.', 'grant', 'NSW', 'https://www.investment.nsw.gov.au/living-working-and-business/nsw-going-global-export-program/', ARRAY['All Sectors'], ARRAY['Growth','Enterprise'], 2000, 10000, NULL, '{"administrator": "NSW Government", "benefit": "Matched funding of up to $10,000 per eligible business.", "eligibility": "NSW-based with ABN/GST registered; min 3 FTE employees; annual turnover up to $100m (or >$100m with >30% export decline); own/produce export goods/services with NSW/Aus value-add", "funding_covers": "50% reimbursement of export market development costs: marketing materials, website internationalisation, e-commerce, market research, trade shows/missions, inbound support, compliance/localisation, IP/insurance"}'::jsonb, false),

('Games Release', 'Games Release supports newer and smaller Victorian games studios to engage experienced consultants to assist them to deliver a well-planned and marketed release of their project.', 'grant', 'Victoria', 'https://vicscreen.vic.gov.au/funding/', ARRAY['Digital Games','Interactive Media'], ARRAY['Startup/Seed','Growth'], NULL, 30000, 'contact@vicscreen.vic.gov.au', '{"administrator": "Film Victoria Australia", "benefit": "Up to $30,000", "eligibility": "Australian companies or citizens/permanent residents based/operating in Victoria for 6+ months prior to application; original digital games (excl. gambling/pay-to-win, educational/training, substantial First Peoples content w/o appropriate key creatives); applicant contributes 50%+ of stage budget", "funding_covers": "Development work, staffing, mentors/consultants, legal/accounting fees; pre-prod: prototype/vertical slice, business dev; prod: release dev, pre-release marketing; post-release: content/DLC, localisation/porting, post-release marketing. Provided as assigned investment (equity to applicant)"}'::jsonb, false),

('Global Innovation Fund (GIF)', 'The Global Innovation Fund invests in social innovations that aim to improve the lives and opportunities of millions of people in the developing world. Through our grants and risk capital, we support breakthrough solutions to global development challenges from social enterprises, for-profit firms, non-profit organisations, researchers, and government agencies. We are global in breadth and scope: open to the best approaches to solve any major development problem in low- or lower-middle income ...', 'grant', 'International', 'https://www.globalinnovation.fund/', ARRAY['Social Innovation','Agriculture','Education','Health','Climate'], ARRAY['Startup/Seed','Growth'], 350000, 23000000, 'hello@globalinnovation.fund', '{"administrator": "Global Innovation Fund", "eligibility": "Innovations improving lives of poor in developing countries more effectively than existing approaches; evidence-informed; scalable to millions; strong team; targets <$5/day PPP (prefer <$2/day or vulnerable groups); any org type (social enterprises, for-profits, non-profits, gov, research); not commonplace/theoretical/single-country limited/not illegal etc.", "funding_covers": "Grants/loans/equity up to USD230k (pilot: test viability), USD2.3M (test/transition: growth/evidence), USD15M (scale: expansion); plus technical assistance, networks, follow-on funding support ; approx. AUD equiv. using 1.5 USD/AUD"}'::jsonb, false),

('Ignite Ideas Fund', 'Ignite Ideas funding is available to commercialise highly innovative and new products or services that are at minimum viable product stage or beyond.', 'grant', 'Queensland', 'https://advance.qld.gov.au/entrepreneurs-and-startups-industry-small-business/ignite-ideas-fund', ARRAY['Technology','Innovation'], ARRAY['Startup/Seed','Series A-B'], NULL, 200000, NULL, '{"administrator": "Advance QLD", "benefit": "Up to $100,000", "eligibility": "QLD-headquartered business, &lt;50 FTE, GST-registered, no prior gov funding for project; cash match (T1:20%, T2:100%); innovative scalable MVP not in market; commercialisation activities only.", "funding_covers": "Commercialisation: new/existing staff salaries (existing capped 20%), external services, equipment &lt;$10k (capped 10%), consumables, travel. Excl. prototypes, BAU, clinical trials."}'::jsonb, false),

('Illumina for Startups - Startups Grant (genomics, sequencing)', '• US$10,000 instrument access to Illumina sequencing kits and reagents • One week of lab work for library prep and/or sequencing on-site in Melbourne, San Francisco or Cambridge, UK. • One business coaching session • Two experiment planning meetings with a senior scientist', 'grant', 'National', 'https://www.illumina.com/science/accelerator/grant-competition.html', ARRAY['Genomics','BioTech','HealthTech'], ARRAY['Startup/Seed','Series A-B'], 10000, 10000, 'startups@illumina.com', '{"administrator": "StartupsAustralia@illumina.com", "benefit": "US$10,000", "eligibility": "Genomics-driven startups; incorporated entity; projects for proof-of-concept sequencing experiments; Australia/Melbourne-based for local program", "funding_covers": "In-kind: 6 months access to MiSeq/NextSeq/NovaSeq systems & reagents in operational lab; technical advice; experiment planning; expert connections (travel/accommodation self-funded)"}'::jsonb, false),

('Innovation Connect Grants', 'The program supports the thriving startup culture in Canberra and empowers entrepreneurs to develop and grow their innovative ideas.', 'grant', 'ACT', 'https://cbrin.com.au/icon', ARRAY['Technology','Innovation'], ARRAY['Pre-Seed','Startup/Seed','Series A-B'], 10000, 30000, 'enquiries@cbrin.com.au', '{"administrator": "Canberra Innovation Network", "benefit": "Matched-funded grants between $10,000-$30,000", "eligibility": "Annual turnover less than $2M or pre-revenue; ABN and GST registered if applicable; registered office/principal place of business in ACT or surrounding region or primarily focused in ACT; not government agency, panel member, or prior recipient", "funding_covers": "Matched funding (GST exclusive) for product development, prototype/software development, marketing plans/strategies (excl. advertising), website upgrades, project-specific staff wages, technical feasibility testing, market testing/customer validation"}'::jsonb, false),

('New Energy Jobs Fund', 'For Victorian social enterprises or NFPs to support the creation of long-term sustainable jobs. Eligible industries: renewable/new energy.', 'grant', 'Victoria', 'https://www.energy.vic.gov.au/grants/new-energy-jobs-fund', ARRAY['Renewable Energy','CleanTech'], ARRAY['Enterprise'], 50000, 1000000, 'new.energy@ecodev.vic.gov.au', '{"administrator": "Environment, Land, Water and Planning Victoria", "benefit": "Apply for a share of $1m", "eligibility": "Victorian-based organizations (incorporated, ABN, 3+ years history); lead org specific types per category (e.g. not-for-profit/local councils for community); projects in Victoria using commercially-ready new energy tech; cash co-contribution required (except encouraged for community); not previously govt-funded activities; no unresolved EPA/WorkSafe issues", "funding_covers": "New energy/renewable projects: business case development (community), implementation/advisory services, manufacturing, tech demos/integration, energy storage pilots; covers salaries, equipment, materials, subcontractors, travel"}'::jsonb, false),

('New Industries Fund', 'The Innovation Vouchers Program can provide your start-up or small business with the financial boost it needs to access professional skills, services or knowledge, enabling you to advance your idea or commercial activity in Western Australia.', 'grant', 'Western Australia', 'https://www.wa.gov.au/organisation/department-of-jobs-tourism-science-and-innovation/new-industries-fund-innovation-booster-grant', ARRAY['Technology','Innovation'], ARRAY['Pre-Seed','Startup/Seed','Series A-B'], NULL, 50000, 'ibg@deed.wa.gov.au', '{"administrator": "WA Government", "benefit": "Up to $40,000 vouchers for eligible expenditure categories", "eligibility": "WA-registered business (ABN/ACN), based in WA for next 3 years, 1-20 employees, solvent, no prior $5M+ capital, pre-revenue innovative project &lt;$100k budget in WA, no prior IBG/similar funding for project, co-contribution (15-20%), external support services only, via Good Grants by deadline", "funding_covers": "External support services for commercialisation: R&D (testing/validation/certification), product dev (design/MVP), IP/tech transfer (protection/licensing/legal), commercialisation (consulting/strategies/studies/financial advice)"}'::jsonb, false),

('R&D Fund', 'Funding for small and medium enterprises (SMEs) and scaleups to commercialise products that address the health, social or economic impacts of the COVID-19 pandemic "Technology-rich startups, scaleups or small to medium enterprises (SMEs) looking to commercialise innovative technology. The core project location must be in NSW. Ineligible projects include activities which largely occur outside of NSW and do not benefit NSW.', 'grant', 'NSW', 'https://treasurynsw.smartygrants.com.au/RDFund', ARRAY['HealthTech','Technology'], ARRAY['Series A-B','Growth'], 250000, 1000000, 'business.innovation@investment.nsw.gov.au', '{"administrator": "Investment NSW", "benefit": "$250,000 to $1 million.", "eligibility": "- NSW-based ABN, operating 12+ months\\n- 75%+ Australian ownership, not >50% owned by another business\\n- $1M+ sales/opex last 12m/fy\\n- Product at TRL 4-9, IP rights, to market in 24m\\n- No prior gov funding for same stage\\n- COVID-19 impact addressing", "funding_covers": "Manufacturing, market/product assessments, salaries/external expertise for project, commercialisation strategies/feasibility studies, specialist equipment/infrastructure"}'::jsonb, false),

('Seed-Start Grant', 'An SA Government grant program that assists innovative early-stage South Australian businesses with high-growth potential to commercialise products or services that could achieve a sustainable competitive advantage in national and international markets. "Grant funding can be provided for a clearly defined project that will generate significant benefits, such as revenue growth, export income, local employment, or other social benefits to South Australia. Seed-Start Grants offer two funding opt...', 'grant', 'South Australia', 'https://industry.sa.gov.au/science-and-research-excellence/rif/stream-2/seed-start', ARRAY['All Sectors'], ARRAY['Startup/Seed','Series A-B'], 50000, 500000, 'rifcontact@sa.gov.au', '{"administrator": "Government of South Australia", "benefit": "$50k - $500k with matched funding requirements dependent on amount", "eligibility": "Australian-incorporated company with active ABN, non-tax-exempt, GST-registered, based/willing to base in South Australia, &lt;$1-2M annual turnover past 3 years; matched cash funding committed; project: innovative product/service with competitive advantage, defined scope generating SA benefits (revenue, jobs, exports)", "funding_covers": "Matched grant funding (Seed 2:1 up to $100k; Start 1:1 up to $500k) for project costs: salaries/consumables, specialist services, IP, prototyping, market research, travel for commercialisation, regulatory approvals (excl. operational costs like rent, founder salaries unless essential)"}'::jsonb, false),

('Seed-Start Program', 'The Seed-Start program equips innovative, early-stage South Australian startups with grant funding to support the commercialisation of an innovative product or service. This product or service must be unique and demonstrate a sustainable competitive advantage in national and international markets. The Seed-Start Program is a stream of the Research and Innovation Fund (RIF) supporting researchers, entrepreneurs and businesses to accelerate their progress with funding from the South Australian ...', 'grant', 'South Australia', 'https://fixe.org.au/community/grants-funding/seed-start', ARRAY['All Sectors'], ARRAY['Startup/Seed','Series A-B','Growth'], 50000, 500000, 'RIFcontact@sa.gov.au', '{"administrator": "FIXE - Future Industries eXchange for Entrepreneurship, Department of Innovation and Skills, Government of South Australia", "benefit": "Matched funding of between $50,000 and $500,000.", "eligibility": "Australian incorporated company with active ABN; non-tax-exempt; GST registered; average annual net sales revenue &lt; $2M over prior 3 years (incl. related entities); based or willing to base in South Australia; commit cash matched funding (2:1 for Seed, 1:1 for Start); no prior SA govt grant for same project", "funding_covers": "Matched grant funding for project costs: salaries/consumables critical to project, specialist services, IP access/protection, product development, scholarships/study tours/market research, travel for testing/market devt/fundraising, data procurement/regulatory approval"}'::jsonb, false);